option.value:
# git-cliff configuration for this template.
# Docs: https://git-cliff.org/docs/configuration

[changelog]
header = """
# Changelog

All notable changes to this project will be documented in this file.
"""
body = """
{% if version %}
## [{{ version | trim_start_matches(pat="v") }}] - {{ timestamp | date(format="%Y-%m-%d") }}
{% else %}
## [Unreleased]
{% endif %}

{% if grouped_commits %}
{% for group, commits in grouped_commits %}
### {{ group }}
{% for commit in commits %}
- {{ commit.message | split(pat="\n") | first | trim }}
{% endfor %}
{% endfor %}
{% else %}
- No user-facing changes in this release.
{% endif %}
"""
trim = true

[git]
conventional_commits = true
filter_unconventional = false
split_commits = false

# Group commits into readable changelog sections.
commit_parsers = [
  { message = "^feat", group = "Added" },
  { message = "^fix", group = "Fixed" },
  { message = "^perf", group = "Performance" },
  { message = "^refactor", group = "Changed" },
  { message = "^docs", group = "Documentation" },
  { message = "^test", group = "Tests" },
  { message = "^chore", group = "Maintenance" },
  { message = "^ci", group = "CI/CD" },
  { body = ".*security", group = "Security" },
]

# Keep commits in chronological order inside each release section.
topo_order = false
sort_commits = "oldest"
